          <Text as="h3" size="lg" weight="semibold">
            With Timestamps
          </Text>
          <TerminalOutput lines={timestampedLines} showTimestamps={true} />
        </Stack>
        <Stack gap="sm">
          <Text as="h3" size="lg" weight="semibold">
            Max Lines (3)
          </Text>
          <TerminalOutput
            lines={[...basicLines, ...errorLines, ...timestampedLines]}
            maxLines={3}
          />
        </Stack>
      </Stack>
    );
  },
};

